p.extended-example:
int ssl, err;
const char *hostname = "example.com";

/* Get a handle, and check the peer's name during handshaking */
ssl = call AcornSSL_Creat, get ssl handle;
call AcornSSL_Setsockopt, SO_ACORNSSL_HOSTNAME, &hostname, 4;

/* Connect; this may trigger the certificate confirmation dialogue */
err = call AcornSSL_Connect, address, addresslen;

/* Read and write the secure connection as usual */
call AcornSSL_Write, ...;
call AcornSSL_Read, ...;

/* Finished */
call AcornSSL_Close;

int sock, ssl;

/* Open and connect an ordinary socket, and talk to it in plain text */
sock = call Socket_Creat, get socket handle;
call Socket_Connect, address, addresslen;
negotiate whether to go secure, in plain text;

/* Hand the socket over to AcornSSL and continue securely */
ssl = call AcornSSL_CreateSession, sock, CreateSession_New;
call AcornSSL_Write, ...;
call AcornSSL_Read, ...;

/* Finished; close the secure session, then the underlying socket */
call AcornSSL_Close;
call Socket_Close, sock;
